function i(e){if(!e)return null;if(e instanceof Date)return e;const t=String(e).trim();if(!t)return null;if(/Z|[+-]\d{2}:?\d{2}$/i.test(t)){const r=new Date(t);return isNaN(r.getTime())?null:r}const o=t.includes("T")?t:t.replace(" ","T"),n=new Date(o+"Z");return isNaN(n.getTime())?null:n}function a(e){const t=i(e);return t?t.toLocaleString("en-IN",{timeZone:"Asia/Kolkata",day:"2-digit",month:"short",year:"numeric",hour:"2-digit",minute:"2-digit",hour12:!0}):""}function u(e){const t=i(e);return t?t.toLocaleDateString("en-IN",{timeZone:"Asia/Kolkata",day:"2-digit",month:"short",year:"numeric"}):""}function c(e){const t=i(e);return t?{date:t.toLocaleDateString("en-IN",{timeZone:"Asia/Kolkata",day:"2-digit",month:"short",year:"numeric"}),time:t.toLocaleTimeString("en-IN",{timeZone:"Asia/Kolkata",hour:"2-digit",minute:"2-digit",hour12:!0})}:{date:"",time:""}}export{c as a,a as b,u as f};
